const keywords = [
  'bittensor', 'tao', 'sn106', 'voidai', 'void ai',
  'subnet', 'decentralized ai', 'chainlink ccip',
  'cross-chain bridge', 'dtao', 'opentensor'
];

const allItems = [];
const feedNodes = ['RSS: CoinDesk', 'RSS: The Block', 'RSS: CoinTelegraph', 'RSS: DL News'];

for (const nodeName of feedNodes) {
  try {
    const feed = $(nodeName).first().json;
    const items = feed?.rss?.channel?.item || feed?.items || feed?.feed?.entry || [];
    const itemList = Array.isArray(items) ? items : [items];

    for (const item of itemList) {
      if (!item) continue;
      const title = (item.title || '').toLowerCase();
      const desc = (item.description || item.summary || item.content || '').toLowerCase();
      const combined = title + ' ' + desc;

      const isRelevant = keywords.some(kw => combined.includes(kw));
      if (isRelevant) {
        allItems.push({
          title: item.title || 'Untitled',
          description: (item.description || item.summary || '').slice(0, 500),
          url: item.link || item.url || item.id || '',
          published: item.pubDate || item.published || item.updated || '',
          source: nodeName.replace('RSS: ', ''),
          type: 'news'
        });
      }
    }
  } catch (e) {
    // Feed unavailable, skip
  }
}

// Deduplicate by URL
const seen = new Set();
const unique = allItems.filter(item => {
  if (!item.url || seen.has(item.url)) return false;
  seen.add(item.url);
  return true;
});

// Check against already-processed items
const fs = require('fs');
const logDir = $env.LOG_FILE_PATH || '/data/n8n/dry-run-logs/';
fs.mkdirSync(logDir, { recursive: true });
const stateFile = logDir + 'news-monitor-state.json';
let state = {};
try {
  state = JSON.parse(fs.readFileSync(stateFile, 'utf8'));
} catch (e) {
  state = { processed_urls: [] };
}

const newItems = unique.filter(item => !state.processed_urls.includes(item.url));

state.processed_urls = [...state.processed_urls, ...newItems.map(i => i.url)].slice(-1000);
fs.writeFileSync(stateFile, JSON.stringify(state, null, 2));

if (newItems.length === 0) {
  return [{ json: { no_new_items: true, scanned: unique.length } }];
}

return newItems.map(item => ({ json: item }));

