const response = $input.first().json;
const originalItem = $('Filter + Deduplicate').first().json;

try {
  const text = response.content?.[0]?.text || '{}';
  // Try to extract JSON from response (may have markdown wrapper)
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  const parsed = JSON.parse(jsonMatch ? jsonMatch[0] : text);

  return [{
    json: {
      ...originalItem,
      score: parsed.score || 0,
      reasoning: parsed.reasoning || '',
      commentary: parsed.commentary || '',
      hashtags: parsed.suggested_hashtags || [],
      scored_at: new Date().toISOString()
    }
  }];
} catch (e) {
  return [{ json: { ...originalItem, score: 0, error: 'Failed to parse Claude response' } }];
}

const fs = require('fs');
const draftsDir = $env.QUEUE_DRAFTS_PATH || '/data/voidai/queue/drafts/';
const item = $input.first().json;
const slug = (item.title || 'untitled').toLowerCase().replace(/[^a-z0-9]+/g, '-').slice(0, 50);
const date = new Date().toISOString().split('T')[0];
const filename = `news-${date}-${slug}.md`;
const filepath = `${draftsDir}${filename}`;

const content = `---
type: x-single
account: "@v0idai"
status: review
created: ${new Date().toISOString()}
source: workflow-4-ecosystem-news
requires_human_review: true
relevance_score: ${item.score}
news_source: ${item.source}
news_url: ${item.url}
---

# News Commentary | ${item.title}

## Original Article
- **Title:** ${item.title}
- **Source:** ${item.source}
- **URL:** ${item.url}
- **Relevance Score:** ${item.score}/10
- **Reasoning:** ${item.reasoning}

## Draft Tweet (${(item.commentary || '').length} chars)

${item.commentary}

## Suggested Hashtags
${(item.hashtags || []).join(' ')}
`;

fs.mkdirSync(draftsDir, { recursive: true });
fs.writeFileSync(filepath, content);

return [{ json: { status: 'drafted', file: filepath, score: item.score, title: item.title } }];

